+		fmt.Fprintf(os.Stderr, "WARN: test dolt server did not become ready on port %d\n", port)
+		_ = serverCmd.Process.Kill()
+		_ = serverCmd.Wait()
+		_ = os.RemoveAll(tmpDir)
+		_ = os.Remove(pidFile)
+		return nil, func() {}
+	}
+
+	srv := &TestDoltServer{
+		Port:    port,
+		cmd:     serverCmd,
+		tmpDir:  tmpDir,
+		pidFile: pidFile,
+	}
+
